text: "Match the following pairs between column 1 and column 2 correctly.",
options: [{"id": "A", "text": "1-a, 2-d, 3-c, 4-b", "is_correct": false}, {"id": "B", "text": "1-d, 2-c, 3-a, 4-b", "is_correct": false}, {"id": "C", "text": "1-a, 2-b, 3-c, 4-d", "is_correct": false}, {"id": "D", "text": "1-b, 2-a, 3-d, 4-c", "is_correct": true}],
