options: [{"id": "A", "text": "a-2, b-1, c-4, d-3", "is_correct": false}, {"id": "B", "text": "a-3, b-1, c-4, d-2", "is_correct": true}, {"id": "C", "text": "a-2, b-4, c-1, d-3", "is_correct": false}, {"id": "D", "text": "a-1, b-2, c-3, d-4", "is_correct": false}],
